@@ -1,24 +1,24 @@
 import Clutter from 'gi://Clutter';
 import GLib from 'gi://GLib';
 import St from 'gi://St';
+import * as Main from 'resource:///org/gnome/shell/ui/main.js';

 export class InputRouter {
-    /**
-     * @param {Clutter.Actor} topWindowGroup - global.top_window_group
-     */
-    constructor(topWindowGroup) {
-        this._topWindowGroup = topWindowGroup;
-
+    constructor() {
         this._stampLayer = new St.Widget({
             name: 'mutter-butter-stamp-layer',
             reactive: false,
             layout_manager: new Clutter.FixedLayout(),
         });
-        // Stamps go in top_window_group for reliable z-ordering.
-        // The grid engine guarantees stamps and full-size windows never
-        // overlap spatially, so z-order is irrelevant — each occupies
-        // its own grid cells.
-        topWindowGroup.add_child(this._stampLayer);
+        // Add as chrome — this puts stamps in the UI layer above windows
+        // but below the panel/popups. Critically, this does NOT add stamps
+        // to window_group, so GNOME Shell's _windowsRestacked won't iterate
+        // our actor and crash on missing meta_window.
+        Main.layoutManager.addChrome(this._stampLayer, {
+            affectsInputRegion: false,
+            affectsStruts: false,
+            trackFullscreen: false,
+        });

         this._previewClone = null;
         this._previewContainer = null;
@@ -92,18 +92,20 @@ export class InputRouter {
             previewY = stampY + container.height + 8;

         this._previewContainer.set_position(previewX, previewY);
-        this._topWindowGroup.add_child(this._previewContainer);
+        Main.layoutManager.addChrome(this._previewContainer, {
+            affectsInputRegion: false,
+            affectsStruts: false,
+        });
         this._previewClone = clone;
     }

     hidePreview() {
         if (this._previewContainer) {
+            Main.layoutManager.removeChrome(this._previewContainer);
             this._previewContainer.destroy();
             this._previewContainer = null;
             this._previewClone = null;
         }
-        // Suppress new previews briefly to prevent re-triggering
